from __future__ import annotations

import argparse
import os
import shlex
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import List, Optional, Tuple


@dataclass(frozen=True)
class ProjectPaths:
    root: Path
    requirements_in: Path
    requirements_txt: Path
    requirements_dev_in: Path
    requirements_dev_txt: Path
    pyproject: Path
    poetry_lock: Path


def _paths(root: Path) -> ProjectPaths:
    return ProjectPaths(
        root=root,
        requirements_in=root / "requirements.in",
        requirements_txt=root / "requirements.txt",
        requirements_dev_in=root / "requirements-dev.in",
        requirements_dev_txt=root / "requirements-dev.txt",
        pyproject=root / "pyproject.toml",
        poetry_lock=root / "poetry.lock",
    )


def run(cmd: List[str], cwd: Optional[Path] = None, check: bool = True) -> int:
    cmd_str = " ".join(shlex.quote(c) for c in cmd)
    print(f"+ {cmd_str}", flush=True)
    p = subprocess.run(cmd, cwd=str(cwd) if cwd else None)
    if check and p.returncode != 0:
        raise SystemExit(p.returncode)
    return p.returncode


def capture(cmd: List[str], cwd: Optional[Path] = None) -> Tuple[int, str, str]:
    cmd_str = " ".join(shlex.quote(c) for c in cmd)
    print(f"+ {cmd_str}", flush=True)
    p = subprocess.run(
        cmd,
        cwd=str(cwd) if cwd else None,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
    )
    return p.returncode, p.stdout, p.stderr


def tool_exists(tool: str) -> bool:
    from shutil import which

    return which(tool) is not None


def detect_mode(paths: ProjectPaths) -> str:
    has_poetry = paths.pyproject.exists()
    has_poetry_lock = paths.poetry_lock.exists()
    has_piptools_inputs = paths.requirements_in.exists() or paths.requirements_dev_in.exists()
    has_piptools_lock = paths.requirements_txt.exists() or paths.requirements_dev_txt.exists()

    if has_poetry_lock or (has_poetry and not has_piptools_inputs):
        return "poetry"
    if has_piptools_inputs or has_piptools_lock:
        return "pip-tools"
    if has_poetry:
        return "poetry"
    return "unknown"


def ensure_files_for_piptools(paths: ProjectPaths) -> None:
    if not paths.requirements_in.exists():
        raise SystemExit(
            "requirements.in not found. Create it with your direct dependencies "
            "(one per line), then re-run."
        )


def compile_piptools(
    paths: ProjectPaths,
    upgrade: bool,
    upgrade_package: Optional[str],
    include_dev: bool,
) -> None:
    ensure_files_for_piptools(paths)

    if not tool_exists("pip-compile"):
        raise SystemExit(
            "pip-compile not found. Install pip-tools: python -m pip install 'pip-tools==7.*'"
        )

    base_cmd = ["pip-compile", "--generate-hashes", "--allow-unsafe", "--strip-extras"]

    if upgrade:
        base_cmd.append("--upgrade")
    if upgrade_package:
        base_cmd += ["--upgrade-package", upgrade_package]

    run(base_cmd + ["-o", str(paths.requirements_txt), str(paths.requirements_in)], cwd=paths.root)

    if include_dev:
        if not paths.requirements_dev_in.exists():
            print("requirements-dev.in not found; skipping dev lock.", file=sys.stderr)
            return
        run(
            base_cmd + ["-o", str(paths.requirements_dev_txt), str(paths.requirements_dev_in)],
            cwd=paths.root,
        )


def install_piptools(paths: ProjectPaths, include_dev: bool) -> None:
    req = paths.requirements_dev_txt if include_dev and paths.requirements_dev_txt.exists() else paths.requirements_txt
    if not req.exists():
        raise SystemExit(f"{req.name} not found. Run compile first.")
    run([sys.executable, "-m", "pip", "install", "--require-hashes", "-r", str(req)], cwd=paths.root)


def verify_piptools(paths: ProjectPaths) -> None:
    if not paths.requirements_txt.exists():
        raise SystemExit("requirements.txt not found. Run compile first.")
    if not tool_exists("pip-compile"):
        raise SystemExit("pip-compile not found. Install pip-tools to verify.")
    # Verify by re-compiling to a temp file and diffing.
    import tempfile
    import difflib

    with tempfile.TemporaryDirectory() as td:
        tmp = Path(td) / "requirements.txt"
        base_cmd = ["pip-compile", "--generate-hashes", "--allow-unsafe", "--strip-extras"]
        rc = run(base_cmd + ["-o", str(tmp), str(paths.requirements_in)], cwd=paths.root, check=False)
        if rc != 0:
            raise SystemExit(rc)
        committed = paths.requirements_txt.read_text(encoding="utf-8").splitlines(keepends=True)
        generated = tmp.read_text(encoding="utf-8").splitlines(keepends=True)
        if committed != generated:
            diff = "".join(difflib.unified_diff(committed, generated, fromfile="requirements.txt", tofile="generated"))
            sys.stderr.write("Lock file out of date: requirements.txt differs from generated output.\n")
            sys.stderr.write(diff)
            raise SystemExit(2)

    if paths.requirements_dev_in.exists() and paths.requirements_dev_txt.exists():
        with tempfile.TemporaryDirectory() as td:
            tmp = Path(td) / "requirements-dev.txt"
            base_cmd = ["pip-compile", "--generate-hashes", "--allow-unsafe", "--strip-extras"]
            rc = run(base_cmd + ["-o", str(tmp), str(paths.requirements_dev_in)], cwd=paths.root, check=False)
            if rc != 0:
                raise SystemExit(rc)
            committed = paths.requirements_dev_txt.read_text(encoding="utf-8").splitlines(keepends=True)
            generated = tmp.read_text(encoding="utf-8").splitlines(keepends=True)
            if committed != generated:
                diff = "".join(
                    difflib.unified_diff(committed, generated, fromfile="requirements-dev.txt", tofile="generated")
                )
                sys.stderr.write("Lock file out of date: requirements-dev.txt differs from generated output.\n")
                sys.stderr.write(diff)
                raise SystemExit(2)

    print("pip-tools lock files verified OK.")


def lock_poetry(paths: ProjectPaths, update: bool = True) -> None:
    if not paths.pyproject.exists():
        raise SystemExit("pyproject.toml not found. Initialize Poetry project first.")
    if not tool_exists("poetry"):
        raise SystemExit("poetry not found. Install: python -m pip install 'poetry==1.8.*'")
    cmd = ["poetry", "lock"]
    if not update:
        cmd.append("--no-update")
    run(cmd, cwd=paths.root)


def verify_poetry(paths: ProjectPaths) -> None:
    if not paths.pyproject.exists():
        raise SystemExit("pyproject.toml not found.")
    if not tool_exists("poetry"):
        raise SystemExit("poetry not found.")
    rc = run(["poetry", "lock", "--check"], cwd=paths.root, check=False)
    if rc != 0:
        raise SystemExit(rc)
    print("poetry.lock verified OK.")


def export_poetry(
    paths: ProjectPaths,
    output: Path,
    with_hashes: bool,
    only_main: bool,
    with_dev: bool,
) -> None:
    if not tool_exists("poetry"):
        raise SystemExit("poetry not found.")
    if not paths.pyproject.exists():
        raise SystemExit("pyproject.toml not found.")

    cmd = ["poetry", "export", "-f", "requirements.txt", "-o", str(output)]

    if with_hashes:
        cmd.append("--with-hashes")

    # Poetry export flags differ across versions; attempt a robust set.
    # Prefer --only main for production; otherwise include dev groups.
    if only_main:
        cmd += ["--only", "main"]
    elif with_dev:
        # For Poetry 1.2+ groups:
        cmd += ["--with", "dev"]
    # else default export includes main dependencies

    rc, out, err = capture(cmd, cwd=paths.root)
    if rc != 0:
        # Fallback for older poetry: use --without dev if only_main requested
        if only_main:
            cmd2 = ["poetry", "export", "-f", "requirements.txt", "-o", str(output)]
            if with_hashes:
                cmd2.append("--with-hashes")
            cmd2 += ["--without", "dev"]
            rc2, out2, err2 = capture(cmd2, cwd=paths.root)
            if rc2 != 0:
                sys.stderr.write(err)
                sys.stderr.write(err2)
                raise SystemExit(rc2)
        else:
            sys.stderr.write(err)
            raise SystemExit(rc)

    print(f"Exported {output}.")


def install_poetry(paths: ProjectPaths, include_dev: bool) -> None:
    if not tool_exists("poetry"):
        raise SystemExit("poetry not found.")
    if include_dev:
        run(["poetry", "install", "--sync", "--with", "dev"], cwd=paths.root)
    else:
        run(["poetry", "install", "--sync", "--only", "main"], cwd=paths.root)


def print_help_text() -> None:
    print(__doc__.strip() + "\n")


def main(argv: Optional[List[str]] = None) -> int:
    argv = argv if argv is not None else sys.argv[1:]
    root = Path(os.getcwd())
    paths = _paths(root)

    p = argparse.ArgumentParser(add_help=False)
    sub = p.add_subparsers(dest="cmd")

    sub.add_parser("help")
    sub.add_parser("detect")

    sp_compile = sub.add_parser("compile")
    sp_compile.add_argument("--mode", choices=["pip-tools", "poetry", "auto"], default="auto")
    sp_compile.add_argument("--upgrade", action="store_true")
    sp_compile.add_argument("--upgrade-package", default=None)
    sp_compile.add_argument("--dev", action="store_true")

    sp_lock = sub.add_parser("lock")
    sp_lock.add_argument("--mode", choices=["poetry", "auto"], default="auto")
    sp_lock.add_argument("--no-update", action="store_true")

    sp_export = sub.add_parser("export")
    sp_export.add_argument("--mode", choices=["poetry", "auto"], default="auto")
    sp_export.add_argument("--output", default="requirements.txt")
    sp_export.add_argument("--with-hashes", action="store_true")
    g = sp_export.add_mutually_exclusive_group()
    g.add_argument("--only-main", action="store_true")
    g.add_argument("--with-dev", action="store_true")

    sp_verify = sub.add_parser("verify")
    sp_verify.add_argument("--mode", choices=["pip-tools", "poetry", "auto"], default="auto")

    sp_install = sub.add_parser("install")
    sp_install.add_argument("--mode", choices=["pip-tools", "poetry", "auto"], default="auto")
    sp_install.add_argument("--dev", action="store_true")

    args = p.parse_args(argv)

    if args.cmd in (None, "help"):
        print_help_text()
        return 0

    mode = None
    if getattr(args, "mode", "auto") == "auto":
        mode = detect_mode(paths)
        if mode == "unknown":
            raise SystemExit(
                "Could not detect dependency management mode. "
                "Use --mode pip-tools or --mode poetry."
            )
    else:
        mode = args.mode

    if args.cmd == "detect":
        print(detect_mode(paths))
        return 0

    if args.cmd == "compile":
        if mode == "pip-tools":
            compile_piptools(
                paths,
                upgrade=bool(args.upgrade),
                upgrade_package=args.upgrade_package,
                include_dev=bool(args.dev),
            )
            return 0
        if mode == "poetry":
            lock_poetry(paths, update=True)
            return 0
        raise SystemExit(f"Unsupported mode for compile: {mode}")

    if args.cmd == "lock":
        if mode != "poetry":
            raise SystemExit("lock command is for Poetry projects. Use compile for pip-tools.")
        lock_poetry(paths, update=not bool(args.no_update))
        return 0

    if args.cmd == "export":
        if mode != "poetry":
            raise SystemExit("export command is for Poetry projects.")
        export_poetry(
            paths,
            output=paths.root / args.output,
            with_hashes=bool(args.with_hashes),
            only_main=bool(args.only_main),
            with_dev=bool(args.with_dev),
        )
        return 0

    if args.cmd == "verify":
        if mode == "pip-tools":
            verify_piptools(paths)
            return 0
        if mode == "poetry":
            verify_poetry(paths)
            return 0
        raise SystemExit(f"Unsupported mode for verify: {mode}")

    if args.cmd == "install":
        if mode == "pip-tools":
            install_piptools(paths, include_dev=bool(args.dev))
            return 0
        if mode == "poetry":
            install_poetry(paths, include_dev=bool(args.dev))
            return 0
        raise SystemExit(f"Unsupported mode for install: {mode}")

    raise SystemExit(f"Unknown command: {args.cmd}")


if __name__ == "__main__":
    raise SystemExit(main())